/**
 * Entity graph workflow
 *
 * Subscribes to entity.upserted, resolves entity<->entity edges via the
 * co-occurrence algorithm, then emits entity.graphed so entity-embed can
 * build its narrative with up-to-date graph context.
 *
 * Extracted from event-interpret.ts — graph resolution has no LLM dependency
 * and should not be blocked by classification latency.
 */

import { log } from "@vendor/observability/log/next";
import { resolveEdges } from "../../lib/edge-resolver";
import { inngest } from "../client";
import { createNeuralOnFailureHandler } from "../on-failure-handler";

export const platformEntityGraph = inngest.createFunction(
  {
    id: "platform/entity.graph",
    name: "Entity Graph",
    description: "Resolves entity edges after upsert (fast, pure SQL)",
    retries: 3,
    timeouts: { finish: "2m" },
    onFailure: createNeuralOnFailureHandler("platform/entity.upserted"),
  },
  { event: "platform/entity.upserted" },
  async ({ event, step }) => {
    const { clerkOrgId, internalEventId, provider, entityRefs, correlationId } =
      event.data;

    const edgeCount = await step.run("resolve-edges", () =>
      resolveEdges(clerkOrgId, internalEventId, provider, entityRefs)
    );

    log.info("edges resolved", {
      internalEventId,
      entityExternalId: event.data.entityExternalId,
      edgeCount,
    });

    await step.sendEvent("emit-entity-graphed", {
      name: "platform/entity.graphed" as const,
      data: {
        clerkOrgId,
        entityExternalId: event.data.entityExternalId,
        entityType: event.data.entityType,
        provider,
        occurredAt: event.data.occurredAt,
        correlationId,
      },
    });

    return { edgeCount };
  }
);

import { backfillDepthSchema } from "@repo/app-providers/client";
import {
  backfillTriggerPayload,
  postTransformEventSchema,
} from "@repo/app-providers/contracts";
import { ingestionSourceSchema } from "@repo/app-validation";
import { z } from "zod";

export const platformEvents = {
  // ── Backfill orchestration events ──
  "platform/backfill.run.requested": backfillTriggerPayload,
  "platform/backfill.run.cancelled": z.object({
    installationId: z.string(),
    correlationId: z.string().max(128).optional(),
  }),
  "platform/backfill.entity.requested": z.object({
    installationId: z.string(),
    provider: z.string(),
    orgId: z.string(),
    entityType: z.string(),
    resource: z.object({
      providerResourceId: z.string(),
      resourceName: z.string(),
    }),
    since: z.string().datetime(),
    depth: backfillDepthSchema,
    holdForReplay: z.boolean().optional(),
    correlationId: z.string().max(128).optional(),
  }),
  // ── Health check signal ──
  "platform/health.check.requested": z.object({
    /** Installation ID of the connection whose token was revoked */
    installationId: z.string(),
    /** Provider name (e.g. "github", "linear") */
    provider: z.string(),
    /** Why the health check is being requested */
    reason: z.enum(["401_unauthorized"]),
    /** Cross-service correlation ID for distributed tracing */
    correlationId: z.string().max(128).optional(),
  }),
  // ── Connection lifecycle (teardown) ──
  "platform/connection.lifecycle": z.object({
    installationId: z.string(),
    orgId: z.string(),
    provider: z.string(),
    reason: z.string(),
    triggeredBy: z.enum(["health_check", "user", "system"]),
    correlationId: z.string().optional(),
  }),
  // ── Ingest + neural pipeline events ──
  "platform/webhook.received": z.object({
    provider: z.string(),
    deliveryId: z.string(),
    eventType: z.string(),
    resourceId: z.string().nullable(),
    payload: z.unknown(),
    receivedAt: z.number(),
    preResolved: z
      .object({
        connectionId: z.string(),
        orgId: z.string(),
      })
      .optional(),
    correlationId: z.string().optional(),
  }),
  "platform/event.capture": z.object({
    clerkOrgId: z.string(),
    sourceEvent: postTransformEventSchema,
    ingestionSource: ingestionSourceSchema.optional(),
    ingestLogId: z.number().optional(),
    correlationId: z.string().optional(),
  }),
  "platform/event.stored": z.object({
    clerkOrgId: z.string(),
    eventExternalId: z.string(),
    sourceType: z.string(),
    significanceScore: z.number(),
    correlationId: z.string().optional(),
  }),
  "platform/entity.upserted": z.object({
    clerkOrgId: z.string(),
    entityExternalId: z.string(),
    entityType: z.string(),
    provider: z.string(),
    internalEventId: z.number(),
    entityRefs: z.array(
      z.object({
        type: z.string(),
        key: z.string(),
        label: z.string().nullable(),
      })
    ),
    occurredAt: z.string(),
    correlationId: z.string().optional(),
  }),
  "platform/entity.graphed": z.object({
    clerkOrgId: z.string(),
    entityExternalId: z.string(),
    entityType: z.string(),
    provider: z.string(),
    occurredAt: z.string(),
    correlationId: z.string().optional(),
  }),
};

/**
 * Inngest exports for platform application
 *
 * Registered functions:
 * 1. ingestDelivery - Webhook delivery -> transform -> emit event.capture
 * 2. platformEventStore - Event pipeline fast path (store facts + entities)
 * 3. platformEntityGraph - Entity edge resolution via co-occurrence
 * 4. platformEntityEmbed - Entity narrative embed to Pinecone layer="entities"
 * 5. platformBackfillOrchestrator - Backfill orchestration (fan-out entity workers)
 * 6. platformEntityWorker - Per-entity-type backfill pagination + dispatch
 * 7. connectionLifecycle - Connection teardown (close gate, revoke, cleanup)
 * 8. healthCheck - 5m cron: probe all active installations
 * 9. tokenRefresh - 5m cron: refresh expiring OAuth tokens
 * 10. deliveryRecovery - 5m cron: sweep stuck webhook deliveries
 * 11. platformRepoIndexSync - Syncs indexed repo content (README.md) on push events
 */

import { serve } from "inngest/next";
import { inngest } from "./client";
import { connectionLifecycle } from "./functions/connection-lifecycle";
import { deliveryRecovery } from "./functions/delivery-recovery";
import { healthCheck } from "./functions/health-check";
import { ingestDelivery } from "./functions/ingest-delivery";
import { platformBackfillOrchestrator } from "./functions/platform-backfill-orchestrator";
import { platformEntityEmbed } from "./functions/platform-entity-embed";
import { platformEntityGraph } from "./functions/platform-entity-graph";
import { platformEntityWorker } from "./functions/platform-entity-worker";
import { platformEventStore } from "./functions/platform-event-store";
import { platformRepoIndexSync } from "./functions/platform-repo-index-sync";
import { tokenRefresh } from "./functions/token-refresh";

export { inngest };
export {
  ingestDelivery,
  platformEventStore,
  platformEntityGraph,
  platformEntityEmbed,
  platformBackfillOrchestrator,
  platformEntityWorker,
  connectionLifecycle,
  healthCheck,
  tokenRefresh,
  deliveryRecovery,
  platformRepoIndexSync,
};

/**
 * Create the Inngest route handler for Next.js
 */
export function createInngestRouteContext() {
  return serve({
    client: inngest,
    functions: [
      ingestDelivery,
      platformEventStore,
      platformEntityGraph,
      platformEntityEmbed,
      platformBackfillOrchestrator,
      platformEntityWorker,
      connectionLifecycle,
      healthCheck,
      tokenRefresh,
      deliveryRecovery,
      platformRepoIndexSync,
    ],
    servePath: "/api/inngest",
  });
}

