1	/**
2	 * Repo Index Sync
3	 *
4	 * Triggered by push webhooks to indexed repos (day 1: .lightfast).
5	 * Fetches README.md and updates the cached content in orgRepoIndexes.
6	 *
7	 * Runs in parallel with ingestDelivery (which marks push events as "skipped").
8	 */
9	
10	import { db } from "@db/app/client";
11	import {
12	  gatewayInstallations,
13	  orgIntegrations,
14	  orgRepoIndexes,
15	} from "@db/app/schema";
16	import type { ProviderDefinition } from "@repo/app-providers";
17	import { getProvider } from "@repo/app-providers";
18	import { NonRetriableError } from "@vendor/inngest";
19	import { log } from "@vendor/observability/log/next";
20	import { and, eq } from "drizzle-orm";
21	import { providerConfigs } from "../../lib/provider-configs";
22	import { getActiveTokenForInstallation } from "../../lib/token-helpers";
23	import { inngest } from "../client";
24	
25	export const platformRepoIndexSync = inngest.createFunction(
26	  {
27	    id: "platform/repo-index.sync",
28	    name: "Repo Index Sync",
29	    description: "Syncs indexed repo content (README.md) on push events",
30	    retries: 3,
31	    timeouts: {
32	      start: "30s",
33	      finish: "2m",
34	    },
35	  },
36	  { event: "platform/webhook.received" },
37	  async ({ event, step }) => {
38	    const data = event.data;
39	
40	    // Only handle push events from GitHub
41	    if (data.provider !== "github" || data.eventType !== "push") {
42	      return { status: "skipped", reason: "not_github_push" };
43	    }
44	
45	    if (!data.resourceId) {
46	      return { status: "skipped", reason: "no_resource_id" };
47	    }
48	
49	    // Step 1: Check if this repo has an active context config
50	    const contextConfig = await step.run("check-context-config", async () => {
51	      const [config] = await db
52	        .select({
53	          id: orgRepoIndexes.id,
54	          clerkOrgId: orgRepoIndexes.clerkOrgId,
55	          integrationId: orgRepoIndexes.integrationId,
56	          contentSha: orgRepoIndexes.contentSha,
57	        })
58	        .from(orgRepoIndexes)
59	        .where(
60	          and(
61	            eq(orgRepoIndexes.providerResourceId, data.resourceId!),
62	            eq(orgRepoIndexes.isActive, true)
63	          )
64	        )
65	        .limit(1);
66	
67	      return config ?? null;
68	    });
69	
70	    if (!contextConfig) {
71	      return { status: "skipped", reason: "no_active_context_config" };
72	    }
73	
74	    // Step 2: Get installation details for API auth
75	    const installationInfo = await step.run(
76	      "resolve-installation",
77	      async () => {
78	        const [integration] = await db
79	          .select({
80	            installationId: orgIntegrations.installationId,
81	          })
82	          .from(orgIntegrations)
83	          .where(eq(orgIntegrations.id, contextConfig.integrationId))
84	          .limit(1);
85	
86	        if (!integration) {
87	          throw new NonRetriableError("integration_not_found");
88	        }
89	
90	        const [installation] = await db
91	          .select({
92	            id: gatewayInstallations.id,
93	            externalId: gatewayInstallations.externalId,
94	            provider: gatewayInstallations.provider,
95	          })
96	          .from(gatewayInstallations)
97	          .where(eq(gatewayInstallations.id, integration.installationId))
98	          .limit(1);
99	
100	        if (!installation) {
101	          throw new NonRetriableError("installation_not_found");
102	        }
103	
104	        return installation;
105	      }
106	    );
107	
108	    // Step 3: Fetch README.md from GitHub
109	    const fileContent = await step.run("fetch-readme", async () => {
110	      const providerDef = getProvider("github");
111	      const config = providerConfigs.github;
112	
113	      const { token } = await getActiveTokenForInstallation(
114	        installationInfo,
115	        config,
116	        providerDef as ProviderDefinition
117	      );
118	
119	      // Extract owner/repo from the push payload
120	      const payload = data.payload as {
121	        repository?: { full_name?: string };
122	      };
123	      const fullName = payload?.repository?.full_name;
124	      if (!fullName) {
125	        throw new NonRetriableError("no_repo_full_name_in_payload");
126	      }
127	
128	      const [owner, repo] = fullName.split("/");
129	
130	      const response = await fetch(
131	        `https://api.github.com/repos/${owner}/${repo}/contents/README.md`,
132	        {
133	          headers: {
134	            Authorization: `token ${token}`,
135	            Accept: "application/vnd.github+json",
136	            "X-GitHub-Api-Version": "2022-11-28",
137	          },
138	        }
139	      );
140	
141	      if (response.status === 404) {
142	        return { found: false as const };
143	      }
144	
145	      if (!response.ok) {
146	        throw new Error(
147	          `GitHub API error: ${response.status} ${response.statusText}`
148	        );
149	      }
150	
151	      const fileData = (await response.json()) as {
152	        content?: string;
153	        sha?: string;
154	      };
155	
156	      if (!fileData.content) {
157	        return { found: false as const };
158	      }
159	
160	      // Skip update if SHA hasn't changed
161	      if (fileData.sha && fileData.sha === contextConfig.contentSha) {
162	        return { found: true as const, unchanged: true as const };
163	      }
164	
165	      const decoded = Buffer.from(fileData.content, "base64").toString("utf-8");
166	      return {
167	        found: true as const,
168	        unchanged: false as const,
169	        content: decoded,
